#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>
#include <string.h>

/*
 * Copy-on-Write Demonstration using fork()
 * 
 * This program demonstrates how Linux/Unix uses COW optimization:
 * - After fork(), parent and child initially share the same physical memory
 * - Pages are marked read-only
 * - Physical copy only happens when either process writes to a page
 */

#define DATA_SIZE 1024 // Size of shared array (multiple pages worth)

int main() {
 // Allocate a buffer that will be shared via COW
 // Using heap allocation so it persists across fork
 int *shared_array = (int *)malloc(DATA_SIZE * sizeof(int));

 if (shared_array == NULL) {
 perror("malloc failed");
 return 1;
 }

 // Initialize the array
 for (int i = 0; i < DATA_SIZE; i++) {
 shared_array[i] = i;
 }

 printf("=== Copy-on-Write Demonstration ===\n\n");
 printf("Parent process (PID: %d) initialized array\n", getpid());
 printf("First element: %d, Last element: %d\n\n", 
 shared_array[0], shared_array[DATA_SIZE-1]);

 // Print memory address to show it's the same virtual address
 printf("Array virtual address: %p\n\n", (void *)shared_array);

 printf("Calling fork()... (COW optimization is applied here)\n");
 printf("No actual memory copying happens at fork() time!\n\n");

 pid_t pid = fork();

 if (pid < 0) {
 // Fork failed
 perror("fork failed");
 free(shared_array);
 return 1;
 }

 if (pid == 0) {
 // Child process
 printf("[CHILD] I am the child (PID: %d)\n", getpid());

 // First, demonstrate reading (no copy triggered)
 printf("[CHILD] Reading array[0] = %d (shared, no copy)\n", 
 shared_array[0]);

 // Now demonstrate writing - this will TRIGGER COW!
 // The kernel will make a private copy for the child
 printf("[CHILD] Writing to array[0] = 999 (triggers COW copy)\n");
 shared_array[0] = 999;

 printf("[CHILD] After modification: array[0] = %d\n", shared_array[0]);
 printf("[CHILD] Array address still: %p (but now in different physical memory)\n",
 (void *)shared_array);

 // Modify more elements to show different pages
 printf("[CHILD] Writing to array[500] = 888\n");
 shared_array[500] = 888;

 printf("[CHILD] Final state: array[0]=%d, array[500]=%d\n\n",
 shared_array[0], shared_array[500]);

 // Child exits
 exit(0);
 } else {
 // Parent process
 printf("[PARENT] I am the parent (PID: %d), child is %d\n", 
 getpid(), pid);

 // Wait for child to complete
 wait(NULL);

 // Check parent's view of the array
 // It should be UNCHANGED because child got its own copy
 printf("\n[PARENT] After child exits\n");
 printf("[PARENT] My array[0] = %d (unchanged, child had private copy)\n",
 shared_array[0]);
 printf("[PARENT] My array[500] = %d (unchanged)\n",
 shared_array[500]);

 printf("\n=== COW Demonstration Complete ===\n");
 printf("Key insight: fork() was fast because no memory was copied.\n");
 printf("Copy only happened when child wrote to memory.\n");

 free(shared_array);
 }

 return 0;
}
